import{_ as a,o as s,c as n,a2 as t}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"CLI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cli.md","filePath":"reference/cli.md","lastUpdated":1783819766000}'),i={name:"reference/cli.md"};function p(o,e,l,r,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h1><p>The package ships a zero-dependency command line tool (stdlib only — no docker, no service process) for inspecting a store from the shell:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wikimem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --store</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./memory</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">comman</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # or: python -m wikimem</span></span></code></pre></div><p><code>--store</code> / <code>-s</code> defaults to the <code>WIKIMEM_STORE</code> environment variable, then the current directory.</p><p>Exit codes follow shell conventions: <code>0</code> ok, <code>1</code> no match / not found, <code>2</code> usage or store errors.</p><h2 id="ls" tabindex="-1"><code>ls</code> <a class="header-anchor" href="#ls" aria-label="Permalink to &quot;\`ls\`&quot;">​</a></h2><p>Categories with item counts:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory ls</span></span>
<span class="line"><span>daily_life      1</span></span>
<span class="line"><span>preferences     2</span></span></code></pre></div><h2 id="show-category-name" tabindex="-1"><code>show &lt;category&gt; [name]</code> <a class="header-anchor" href="#show-category-name" aria-label="Permalink to &quot;\`show &lt;category&gt; [name]\`&quot;">​</a></h2><p>Prints a category — or a single item — exactly the way the file stores it (headings, content, provenance comment):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory show preferences likes-the-sea</span></span>
<span class="line"><span>## likes-the-sea</span></span>
<span class="line"><span></span></span>
<span class="line"><span>喜欢海边，提到过想去海边玩。[[daily_life:beach-trip-plan]]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;!-- wikimem: owner=user:xnne | ts=2026-07-10T03:00:00+00:00 --&gt;</span></span></code></pre></div><h2 id="grep-pattern-i" tabindex="-1"><code>grep &lt;pattern&gt; [-i]</code> <a class="header-anchor" href="#grep-pattern-i" aria-label="Permalink to &quot;\`grep &lt;pattern&gt; [-i]\`&quot;">​</a></h2><p>Regex search over item names and content, grep-style output prefixed with <code>category:name</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory grep 海边</span></span>
<span class="line"><span>preferences:likes-the-sea:喜欢海边，提到过想去海边玩。[[daily_life:beach-trip-plan]]</span></span>
<span class="line"><span>daily_life:beach-trip-plan:计划夏天去海边旅行，看日出。</span></span></code></pre></div><h2 id="explain-query" tabindex="-1"><code>explain &quot;&lt;query&gt;&quot;</code> <a class="header-anchor" href="#explain-query" aria-label="Permalink to &quot;\`explain &quot;&lt;query&gt;&quot;\`&quot;">​</a></h2><p>Runs real retrieval (<code>MemoryIndex.retrieve(..., explain=True)</code>) and prints the scoring breakdown: ranked hits, one-hop link expansions with their parent, token estimates, the budget cut, and dangling links.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory explain &quot;想去海边玩&quot;</span></span>
<span class="line"><span>query: 想去海边玩</span></span>
<span class="line"><span>query tokens: 想去, 去海, 海边, 边玩</span></span>
<span class="line"><span>ranking: BM25 (embedding: off)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  #  src      score     bm25    cos  ~tok  item</span></span>
<span class="line"><span>  1  hit     1.676    1.676      -     22  preferences:likes-the-sea  [去海, 海边, ...]</span></span>
<span class="line"><span>  2  link        -        -      -     15  daily_life:beach-trip-plan  (via likes-the-sea)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>budget: used 37 / no limit</span></span>
<span class="line"><span>unresolved links: [[missing:gone]]</span></span></code></pre></div><p>Flags: <code>--limit N</code> (ranked hits, default 10), <code>--budget N</code> (token budget — dropped entries are listed), <code>--no-links</code> (disable one-hop expansion), <code>--jieba</code> / <code>--no-jieba</code> (force the CJK tokenizer path; default auto).</p><p>The CLI always runs the BM25 path — embedding fusion needs an endpoint and belongs to host configuration, not shell inspection.</p><h2 id="graph-format-mermaid-json" tabindex="-1"><code>graph [--format mermaid|json]</code> <a class="header-anchor" href="#graph-format-mermaid-json" aria-label="Permalink to &quot;\`graph [--format mermaid|json]\`&quot;">​</a></h2><p>Parses <code>[[category:item]]</code> links out of the markdown and exports the wiki-link relation graph. This is the replacement for the retired Neo4j semantic-layer visualization: no infrastructure, same picture.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory graph</span></span>
<span class="line"><span>graph LR</span></span>
<span class="line"><span>    n0[&quot;daily_life:beach-trip-plan&quot;]</span></span>
<span class="line"><span>    n1[&quot;preferences:likes-the-sea&quot;]</span></span>
<span class="line"><span>    n2[&quot;missing:gone&quot;]:::unresolved</span></span>
<span class="line"><span>    n1 --&gt; n0</span></span>
<span class="line"><span>    n1 --&gt; n2</span></span>
<span class="line"><span>    classDef unresolved stroke-dasharray: 5 5;</span></span></code></pre></div><p>Paste mermaid output straight into any markdown renderer. Link targets that don&#39;t exist in the store are kept as dashed <code>unresolved</code> nodes so dangling references stay visible.</p><p><code>--format json</code> emits <code>{&quot;nodes&quot;: [...], &quot;edges&quot;: [...]}</code> (each node: <code>id</code> / <code>category</code> / <code>name</code> / <code>unresolved</code>) for host frontends to render themselves.</p>`,24)])])}const g=a(i,[["render",p]]);export{m as __pageData,g as default};
